function get_unit_activity_text(punit)
{
  var activity = punit['activity'];

  /* don't draw activity for enemy units */
  if (client.conn.playing == null || punit['owner'] != client.conn.playing.playerno) {
    return null;
  }

  switch (activity) {
    case ACTIVITY_CLEAN:
    case ACTIVITY_POLLUTION:
      return "c";

    case ACTIVITY_MINE:
      return "m";

    case ACTIVITY_PLANT:
      return "M";

    case ACTIVITY_IRRIGATE:
      return "i";

    case ACTIVITY_CULTIVATE:
      return "I";

    case ACTIVITY_FORTIFIED:
      return "F";

    case ACTIVITY_BASE:
      return "B";

    case ACTIVITY_SENTRY:
      return "S";

    case ACTIVITY_PILLAGE:
      return "P";

    case ACTIVITY_GOTO:
      return "G";

    case ACTIVITY_EXPLORE:
      return "X";

    case ACTIVITY_TRANSFORM:
      return "T";

    case ACTIVITY_FORTIFYING:
      return "F";

    case ACTIVITY_GEN_ROAD:
      return "R";

    case ACTIVITY_CONVERT:
      return "C";
  }

  if (unit_has_goto(punit)) {
    return "G";
  }

  switch (punit['ssa_controller']) {
  case SSA_NONE:
    break;
  case SSA_AUTOSETTLER:
    return "A";
  case SSA_AUTOEXPLORE:
    return "X";
  }

  return null;
}


